      });
      expect(result[1]).toMatchObject({
        path: 'clients/widgets-inc/integration.md',
        target: { clientId: 'widgets-inc' }
      });
    });

    it('should handle multiple commits in a single push', () => {
      const pushPayload = {
        ref: 'refs/heads/main',
        repository: {
          name: 'knowledge-base',
          full_name: 'askkaya/knowledge-base'
        },
        commits: [
